scwin.ds_DetailInfo_onloadcompleted = async function (e) {
  let rowcnt = ds_DetailInfo.getRowCount();
  totalRows.setValue(rowcnt);
  $c.gus.cfGoPrevPosition($p, ds_DetailInfo, scwin.preRowPos);
  scwin.f_Set("SAVE");
  if (rowcnt == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    scwin.f_Set("INIT");
  } else {
    scwin.f_ContractInfo();
  }
  gr_DetailInfo.setColumnProperty("item", "readOnly", true);
  gr_DetailInfo.setColumnProperty("fcode", "readOnly", true);
  gr_DetailInfo.setColumnProperty("curr", "readOnly", true);
  gr_DetailInfo.setColumnProperty("type", "readOnly", true);
};
