scwin.gr_DetailInfo_ontextimageclick = function (rowIndex, columnIndex, columnId) {
  switch (columnId) {
    case "cust":
      scwin.f_PopUpGrid("Customer", rowIndex, "F", "F");
      break;
    case "liner":
      scwin.f_PopUpGrid("Liner", rowIndex, "F", "F");
      break;
    case "portFrom":
      scwin.f_PopUpGrid("Loading", rowIndex, "F", "F");
      break;
    case "portTo":
      scwin.f_PopUpGrid("Discharge", rowIndex, "F", "F");
      break;
    case "item":
      scwin.f_PopUpGrid("Item", rowIndex, "F", "F");
      break;
    case "fcode":
      scwin.f_PopUpGrid("Freight", rowIndex, "F", "F");
      break;
    case "type":
      scwin.f_PopUpGrid("CNTR_TYPE", rowIndex, "F", "F");
      break;
    case "curr":
      scwin.f_PopUpGrid("Currency", rowIndex, "F", "F");
      break;
    case "apdtFrom":
      $c.gus.cfOpenCalendar($p, gr_DetailInfo, rowIndex, columnId);
      break;
    case "apdtTo":
      $c.gus.cfOpenCalendar($p, gr_DetailInfo, rowIndex, columnId);
      break;
    default:
      break;
  }
};
scwin.gr_DetailInfo_oneditend = function (rowIndex, columnId, oldValue, newValue) {
  if (rowIndex >= 0 && ds_DetailInfo.getRowCount() > rowIndex) {
    switch (columnId) {
      case "cust":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("Customer", rowIndex, "T", "F");
        }
        break;
      case "liner":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("Liner", rowIndex, "T", "F");
        }
        break;
      case "portFrom":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("Loading", rowIndex, "T", "F");
        }
        break;
      case "portTo":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("Discharge", rowIndex, "T", "F");
        }
        break;
      case "item":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("Item", rowIndex, "T", "F");
        }
        break;
      case "fcode":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          ds_DetailInfo.setCellData(rowIndex, "selpchItemCd", "");
          scwin.f_PopUpGrid("Freight", rowIndex, "T", "F");
        }
        break;
      case "type":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("CNTR_TYPE", rowIndex, "T", "F");
        }
        break;
      case "curr":
        if (ds_DetailInfo.getCellData(rowIndex, columnId).trim() != "" && ds_DetailInfo.getCellData(rowIndex, columnId) != oldValue) {
          scwin.f_PopUpGrid("Currency", rowIndex, "T", "F");
        }
        break;
      default:
        break;
    }
  }
};
